def get_group_filters(self, obj):
        ctype = get_content_type(obj)
        model = get_group_obj_perms_model(obj)
        related_name = model.permission.field.related_query_name()

        if self.user:
            group_filters = {f"{related_name}__group__in": self.user.groups.all()}
        else:
            group_filters = {f"{related_name}__group": self.group}

        if model.objects.is_generic():
            group_filters.update({
                "%s__content_type" % related_name: ctype,
                "%s__object_pk" % related_name: obj.pk,
            })
        else:
            group_filters["%s__content_object" % related_name] = obj

        return group_filters

def filter_users_by_username(*username) -> models.QuerySet[AbstractBaseUser]:
    if app_settings.PRESERVE_USERNAME_CASING:
        qlist = [
            Q(**{f"{app_settings.USER_MODEL_USERNAME_FIELD}__iexact": u})
            for u in username
        ]
        q = qlist[0]
        for q2 in qlist[1:]:
            q = q | q2
        ret = get_user_model()._default_manager.filter(q)
    else:
        ret = get_user_model()._default_manager.filter(
            **{
                f"{app_settings.USER_MODEL_USERNAME_FIELD}__in": [
                    u.lower() for u in username
                ]
            }
        )
    return ret

def filter_where_by_numeric_field(
    qs: "QuerySet",
    field: str,
    value: dict[str, Number | list[Number] | dict[str, Number]],
):
    if not value:
        return qs.none()

    one_of = value.get("one_of")
    range = value.get("range")

    if "eq" in value:
        # allow filtering by `None` value
        return qs.filter(**{field: value["eq"]})
    if one_of:
        return qs.filter(**{f"{field}__in": one_of})
    if range and isinstance(range, dict):
        lte = range.get("lte")
        gte = range.get("gte")
        if lte is None and gte is None:
            return qs.none()
        if lte is not None:
            qs = qs.filter(**{f"{field}__lte": lte})
        if gte is not None:
            qs = qs.filter(**{f"{field}__gte": gte})
        return qs
    return qs.none()

def get_used_space_in_data_centers(data_centers):
    used_by_accessories = (
        RackAccessory.objects.filter(
            rack__server_room__data_center__in=data_centers,
        )
        .values_list("rack__server_room__data_center__name")
        .annotate(s=Count("rack"))
    )
    used_by_assets = (
        DataCenterAsset.objects.filter(
            rack__server_room__data_center__in=data_centers,
            model__has_parent=False,
            rack__require_position=True,
        )
        .values_list("rack__server_room__data_center__name")
        .annotate(s=Sum("model__height_of_device"))
    )
    return Counter(dict(used_by_assets)) + Counter(dict(used_by_accessories))

def post(self, request, *args, **kwargs):
        if request.customer.is_visitor:
            customer = CustomerModel.objects.get_or_create_from_request(request)
        else:
            customer = request.customer
        form_data = request.data.get(self.form_class.scope_prefix, {})
        form = self.form_class(data=form_data, instance=customer)
        if form.is_valid():
            form.save(request=request)
            response_data = {form.form_name: {
                'success_message': _("Successfully registered yourself."),
            }}
            return Response(response_data, status=status.HTTP_200_OK)
        errors = dict(form.errors)
        if 'email' in errors:
            errors.update({NON_FIELD_ERRORS: errors.pop('email')})
        return Response({form.form_name: errors}, status=status.HTTP_422_UNPROCESSABLE_ENTITY)

def handle(self, *args, **options):
        style = no_style() if options["no_color"] else color_style()

        self.names = defaultdict(list)
        self.views = {}

        self.collect_templates(options)
        self.collect_views(options)

        for name in sorted(self.names):
            n = len(self.names[name])
            color = style.MODULE
            try:
                v = self.views[name]
                print(
                    style.INFO(
                        f"Name: {name} ({n} occurrences, handled in {v[0]}, {v[1]})"
                    )
                )
            except KeyError:
                print(style.URL_NAME(f"Name: {name} ({n} occurrences, UNKNOWN VIEW)"))
                color = style.URL_NAME
            for item in self.names[name]:
                print(color(f"* {item[0]}:{item[1]}"))

def generate_enum_name(django_model_meta, field):
    if graphene_settings.DJANGO_CHOICE_FIELD_ENUM_CUSTOM_NAME:
        # Try and import custom function
        custom_func = import_string(
            graphene_settings.DJANGO_CHOICE_FIELD_ENUM_CUSTOM_NAME
        )
        name = custom_func(field)
    elif graphene_settings.DJANGO_CHOICE_FIELD_ENUM_V2_NAMING is True:
        name = to_camel_case(f"{django_model_meta.object_name}_{field.name}")
    else:
        name = "{app_label}{object_name}{field_name}Choices".format(
            app_label=to_camel_case(django_model_meta.app_label.title()),
            object_name=django_model_meta.object_name,
            field_name=to_camel_case(field.name.title()),
        )
    return name

def get_cache_key(
    request: HttpRequest, *, action: str, rate: Rate, key=None, user=None
) -> str:
    source: tuple[str, ...]
    if rate.per == "ip":
        source = ("ip", get_ip(request))
    elif rate.per == "user":
        if user is None:
            if not request.user.is_authenticated:
                raise ImproperlyConfigured(
                    "ratelimit configured per user but used anonymously"
                )
            user = request.user
        source = ("user", str(user.pk))
    elif rate.per == "key":
        if key is None:
            raise ImproperlyConfigured(
                "ratelimit configured per key but no key specified"
            )
        key_hash = hashlib.sha256(key.encode("utf8")).hexdigest()
        source = (key_hash,)
    else:
        raise ValueError(rate.per)
    keys = ["allauth", "rl", action, *source]
    return ":".join(keys)

def get_results(queryset, can_edit, prepend_empty=False):
    results = []
    if prepend_empty:
        results.append(
            {
                "pk": AUTOCOMPLETE_EMPTY_VALUE,
                "__str__": AUTOCOMPLETE_EMPTY_LABEL,
            }
        )
    results.extend(
        [
            {
                "pk": obj.pk,
                "__str__": getattr(obj, "autocomplete_str", str(obj)),
                "edit_url": "{}?_popup=1".format(get_admin_url(obj, "change"))
                if can_edit
                else None,
                "tooltip": getattr(obj, "autocomplete_tooltip", None),
            }
            for obj in queryset
        ]
    )
    return results

def __call__(self, view):
        admin_model = ralph_site._registry[self.target_model]
        if not issubclass(view, RalphExtraViewMixin):
            raise ValueError(
                "The view must be inherited from RalphDetailView or RalphListView"
            )
        if view._type not in VIEW_TYPES:
            raise ValueError(
                "The view._type must be a one of defined choices ({}).".format(
                    ", ".join(VIEW_TYPES)
                )
            )
        if view._type == LIST:
            admin_model.list_views = admin_model.list_views or []
            admin_model.list_views.append(view)
        if view._type == CHANGE:
            admin_model.change_views = admin_model.change_views or []
            admin_model.change_views.append(view)
        view.post_register(ralph_site.name, self.target_model)
        return view

def queryset(self, request, queryset):
        if any(self.value()):
            date = self.value()
            try:
                date_start = datetime.strptime(
                    date[0], get_format("DATE_INPUT_FORMATS")[0]
                )
                queryset = queryset.filter(
                    **{
                        "{}__gte".format(self.field_path): date_start,
                    }
                )
            except ValueError:
                pass

            try:
                date_end = datetime.strptime(
                    date[1], get_format("DATE_INPUT_FORMATS")[0]
                )
                queryset = queryset.filter(
                    **{
                        "{}__lte".format(self.field_path): date_end,
                    }
                )
            except ValueError:
                pass

            return queryset

def queryset(self, request, queryset):
        value = self.value()
        if not value:
            ids = []
        else:
            ids = value.split(",")
        q_param = models.Q()
        for id_ in ids:
            if id_ == self.empty_value:
                q_param |= Q(**{"{}__isnull".format(self.field_path): True})
            else:
                q_param |= Q(**{self.field_path: id_})
        try:
            queryset = queryset.filter(q_param)
        except ValueError:
            _add_incorrect_value_message(request, self.title)
            raise IncorrectLookupParameters()
        # distinct for m2m
        return queryset.distinct()

def __new__(cls, name, bases, attrs):
        meta = attrs.get("Meta")
        model = getattr(meta, "model", None)
        fields = getattr(meta, "fields", None)
        if (
            model
            and issubclass(model, TaggableMixin)
            and not getattr(attrs.get("Meta"), "_skip_tags_field", False)
        ):
            attrs["tags"] = TagListSerializerField(required=False)
            attrs["prefetch_related"] = list(attrs.get("prefetch_related", [])) + [
                "tags"
            ]

        if model and issubclass(model, AdminAbsoluteUrlMixin):
            attrs["ui_url"] = AbsoluteUrlField()
            if fields and isinstance(fields, (list, tuple)):
                meta.fields += ("ui_url",)
        return super().__new__(cls, name, bases, attrs)

def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        choices = [
            ct
            for ct in ContentType.objects.all()
            if getattr(ct.model_class(), "_allow_in_dashboard", False)
        ]

        def keyfunc(x):
            return x.app_label

        data = sorted(choices, key=keyfunc)
        self.fields["model"] = forms.ChoiceField(
            choices=(
                (k.capitalize(), list(map(lambda x: (x.id, x), g)))
                for k, g in groupby(data, keyfunc)
            )
        )

        self.initial["params"] = json.dumps(
            self.initial.get("params", {}), indent=4, sort_keys=True
        )

def _validate_mgmt_ip_is_unique(self):
        if not self.cleaned_data.get("management_ip"):
            return
        try:
            ip = IPAddress.objects.get(
                address=self.cleaned_data["management_ip"],
            )
        except IPAddress.DoesNotExist:
            pass
        else:
            if ip.base_object and ip.base_object.pk != self.instance.pk:
                ip_obj = ip.base_object.last_descendant
                msg = _(
                    "Management IP is already assigned to "
                    '<a target="_blank" href="{}">{}</a>'
                ).format(ip_obj.get_absolute_url(), ip_obj)
                exc = ValidationError({"management_ip": mark_safe(msg)})
                self._update_errors(exc)

def _is_valid(self):
        is_valid, error = self._objects_are_valid()
        if not is_valid:
            messages.info(self.request, _("Some assets are not valid"))
            additional_error_message = "<ul>"
            for obj, msgs in error.errors.items():
                additional_error_message += "<li>"
                additional_error_message += '<a href="{}">{}</a> - {}'.format(
                    obj.get_absolute_url(), obj, ",".join(map(str, msgs))
                )
                additional_error_message += "</li>"
            additional_error_message += "</ul>"
            messages.error(
                self.request,
                mark_safe("{}<br>{}".format(error.message, additional_error_message)),
            )
            return HttpResponseRedirect("..")
        return None

def update_dns_record(instance, created, *args, **kwargs):
    if not _should_send_dnsaas_request(instance):
        return
    keys = ["address", "hostname"]
    old = {key: instance._previous_state[key] for key in keys}
    new = {key: instance.__dict__[key] for key in keys}
    if old != new and old["hostname"] is not None:
        data_to_send = {
            "old": old,
            "new": new,
            "service_uid": _get_connected_service_uid(instance),
            "action": "add" if created else "update",
        }
        DNSaaS().send_ipaddress_data(data_to_send)

def post(self, request, uidb64=None, token=None):
        try:
            data = dict(request.data['form_data'], uid=uidb64, token=token)
        except (KeyError, TypeError, ValueError):
            errors = {'non_field_errors': [_("Invalid POST data.")]}
        else:
            serializer = self.get_serializer(data=data)
            if serializer.is_valid():
                serializer.save()
                response_data = {self.form_name: {
                    'success_message': _("Password has been reset with the new password."),
                }}
                return Response(response_data)
            else:
                errors = serializer.errors
        return Response({self.form_name: errors}, status=status.HTTP_422_UNPROCESSABLE_ENTITY)

def _get_osfstorage_file_version_and_node(
    file_path: str,
    file_version_id: str = None
):  # -> tuple[FileVersion, OsfStorageFileNode]
    if not file_path:
        return None, None

    file_node = OsfStorageFileNode.load(file_path.strip('/'))
    if not (file_node and file_node.is_file):
        return None, None

    try:
        file_version = FileVersion.objects.select_related('region').get(
            basefilenode=file_node,
            identifier=file_version_id or str(file_node.versions.count())
        )
    except FileVersion.DoesNotExist:
        raise HTTPError(http_status.HTTP_400_BAD_REQUEST, 'Requested File Version unavailable')

    return file_version, file_node

def post(self, request, *args, **kwargs):
        node = self.get_object()
        new_private_cap = request.POST.get('private-cap-input')
        new_public_cap = request.POST.get('public-cap-input')

        node_private_cap = node.custom_storage_usage_limit_private or settings.STORAGE_LIMIT_PRIVATE
        node_public_cap = node.custom_storage_usage_limit_public or settings.STORAGE_LIMIT_PUBLIC

        if float(new_private_cap) != node_private_cap:
            node.custom_storage_usage_limit_private = new_private_cap

        if float(new_public_cap) != node_public_cap:
            node.custom_storage_usage_limit_public = new_public_cap

        node.save()
        return redirect(self.get_success_url())

