def from_dir(self, options):
        file_list = []
        for path in glob.glob(os.path.join(options.get("source"), "*.csv")):
            base_name = os.path.basename(path)
            file_name = os.path.splitext(base_name)[0].split("_")
            file_list.append(
                {"model": file_name[1], "path": path, "sort": int(file_name[0])}
            )
        file_list = sorted(file_list, key=lambda x: x["sort"])
        for item in file_list:
            logger.info("Import to model: {}".format(item["model"]))
            options["model_name"] = item["model"]
            options["source"] = item["path"]
            self.from_file(options)

def _get_oauth_token(self):
        client_id = settings.OAUTH_CLIENT_ID
        secret = settings.OAUTH_SECRET
        token_url = settings.OAUTH_TOKEN_URL
        client = BackendApplicationClient(client_id=client_id)
        oauth = OAuth2Session(client=client)
        try:
            token = oauth.fetch_token(
                token_url=token_url, client_id=client_id, client_secret=secret
            )
        except CustomOAuth2Error as e:
            logger.error(str(e))

        expire_in = token.get("expires_in")
        self.token_expiration = datetime.now() + timedelta(0, expire_in - 60)
        return token.get("access_token")

def _get_token_scopes_from_cas(auth_header):
    client = cas.get_client()
    try:
        access_token = cas.parse_auth_header(auth_header)
        cas_resp = client.profile(access_token)
    except cas.CasError as e:
        sentry.log_exception(e)
        raise HTTPError(http_status.HTTP_403_FORBIDDEN)

    if not cas_resp.authenticated:
        raise HTTPError(
            http_status.HTTP_403_FORBIDDEN, 'Failed to authenticate via provided Bearer Token'
        )

    return oauth_scopes.normalize_scopes(cas_resp.attributes.get('accessTokenScope', []))

def get_bucket_prefixes(access_key, secret_key, prefix, bucket_name):
    s3 = boto3.client(
        's3',
        aws_access_key_id=access_key,
        aws_secret_access_key=secret_key
    )

    result = s3.list_objects(Bucket=bucket_name, Prefix=prefix, Delimiter='/')
    folders = []
    for common_prefixes in result.get('CommonPrefixes', []):
        key_name = common_prefixes.get('Prefix')
        if key_name != prefix:
            folders.append(
                {
                    'path': key_name,
                    'id': f'{bucket_name}:/{key_name}',
                    'folder_id': key_name,
                    'kind': 'folder',
                    'bucket_name': bucket_name,
                    'name': key_name.split('/')[-2],
                    'addon': 's3',
                }
            )

    return folders

